// Importing necessary modules
const cron = require('node-cron');
const mongoose = require('mongoose');
const NotificationLog = require('./models/NotificationLog'); // Assuming NotificationLog model is implemented
const Task = require('./models/Task'); // Assuming Task model is implemented

/**
 * Scheduling Engine Class
 * Handles all scheduling and notification functionalities
 */
class SchedulingEngine {
  constructor() {
    this.scheduleTasks();
  }

  /**
   * Schedules tasks based on their recurrence
   */
  scheduleTasks() {
    // Fetching tasks from the database
    Task.find({ status: 'active' }).then(tasks => {
      tasks.forEach(task => {
        const scheduleTime = this.getCronSchedule(task);
        cron.schedule(scheduleTime, () => {
          this.sendNotification(task);
        });
      });
    }).catch(error => {
      console.error('Error fetching tasks:', error);
    });
  }

  /**
   * Constructs cron expression based on the task's recurrence
   * @param {Object} task - The task object
   * @returns {String} cronExpression - The cron expression for scheduling
   */
  getCronSchedule(task) {
    const { recurrence } = task;
    if (recurrence.type === 'daily') {
      return `0 ${recurrence.time.split(':')[1]} ${recurrence.time.split(':')[0]} * * *`; // Using UTC+7
    } else if (recurrence.type === 'weekly') {
      const days = recurrence.daysOfWeek.join(',');
      return `0 ${recurrence.time.split(':')[1]} ${recurrence.time.split(':')[0]} * * ${days}`;
    } else {
      // Custom logic if needed
      return '* * * * *'; // Every minute as a fallback
    }
  }

  /**
   * Sends notification to the assigned members
   * @param {Object} task - The task to send notification for
   */
  sendNotification(task) {
    // Logic to send notification (e.g., via Telegram)
    console.log(`Sending notification for task: ${task.title}`);
    // Log the notification in the database
    const log = new NotificationLog({ taskId: task.id, sentAt: new Date(), status: 'success' });
    log.save().catch(error => {
      console.error('Error logging notification:', error);
    });
  }
}

// Initialize the scheduling engine
new SchedulingEngine();
